        const resolved = (cell.ceremony ?? 0) + (cell.prevented ?? 0);
        sig1Label = 'CER'; sig1Pct = pct(cell.ceremony ?? 0, resolved);
        sig2Label = 'PRV'; sig2Pct = pct(cell.prevented ?? 0, resolved);
